INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.1.1.1', 'C', 'Disemak Fail 1: Polisi MSPO, Polisi KKP, Polisi Alam Sekitar, Polisi Sosial, Anti Rasuah, Whistleblower. Bukti mencukupi bagi klausa 4.1.1.1 berkaitan Polisi MSPO diluluskan pengurusan atasan (bertarikh) & tersedia awam. Pematuhan dapat disahkan semasa audit.', 'Kekalkan rekod, kawalan versi dan bukti pelaksanaan. Pastikan dokumen mudah dicapai untuk audit seterusnya.', 'Fail 1: Polisi MSPO, Polisi KKP, Polisi Alam Sekitar, Polisi Sosial, Anti Rasuah, Whistleblower', 'Semak paparan polisi di pejabat, stor, pondok rehat dan kawasan pekerja.', 'N/A tidak digalakkan untuk klausa ini kecuali terdapat justifikasi sah. Auditor perlu merekodkan justifikasi khusus sebelum memilih N/A.') ON CONFLICT (klausa_kod, status) DO NOTHING;
INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.1.1.1', 'OFI', 'Disemak Fail 1: Polisi MSPO, Polisi KKP, Polisi Alam Sekitar, Polisi Sosial, Anti Rasuah, Whistleblower. Bukti tersedia tetapi masih boleh diperkukuh atau belum lengkap sepenuhnya bagi klausa 4.1.1.1 berkaitan Polisi MSPO diluluskan pengurusan atasan (bertarikh) & tersedia awam.', 'Lengkapkan bukti sokongan, kemas kini rekod, tetapkan PIC dan nyatakan tempoh tindakan bagi penambahbaikan.', 'Fail 1: Polisi MSPO, Polisi KKP, Polisi Alam Sekitar, Polisi Sosial, Anti Rasuah, Whistleblower', 'Semak paparan polisi di pejabat, stor, pondok rehat dan kawasan pekerja.', 'N/A tidak digalakkan untuk klausa ini kecuali terdapat justifikasi sah. Auditor perlu merekodkan justifikasi khusus sebelum memilih N/A.') ON CONFLICT (klausa_kod, status) DO NOTHING;
