INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.1.3.4', 'C', 'Disemak Fail 5: Peta Blok/Division Ladang. Bukti mencukupi bagi klausa 4.1.3.4 berkaitan Papan tanda visual dipasang (blok, luas, tarikh tanam, klon/varieti). Pematuhan dapat disahkan semasa audit.', 'Kekalkan rekod, kawalan versi dan bukti pelaksanaan. Pastikan dokumen mudah dicapai untuk audit seterusnya.', 'Fail 5: Peta Blok/Division Ladang', 'Semak papan tanda di blok, sempadan dan kawasan operasi.', 'N/A tidak digalakkan untuk klausa ini kecuali terdapat justifikasi sah. Auditor perlu merekodkan justifikasi khusus sebelum memilih N/A.') ON CONFLICT (klausa_kod, status) DO NOTHING;
