INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.1.6.3', 'C', 'Berdasarkan semakan Fail 4: Bajet Tanaman Semula (3-5 Tahunan); Fail 9: Panduan Kos Standard. Bukti mencukupi bagi klausa 4.1.6.3 berkaitan Program penanaman semula jangka panjang hendaklah diwujudkan dan dikaji semula setiap tahun. Pematuhan dapat disahkan semasa audit.', 'Kekalkan rekod, kawalan versi dan bukti pelaksanaan. Pastikan dokumen mudah dicapai untuk audit seterusnya.', 'Fail 4: Bajet Tanaman Semula (3-5 Tahunan); Fail 9: Panduan Kos Standard', 'Semak program tanam semula jangka panjang dan tarikh semakan.', 'N/A hanya sesuai jika tiada program atau aktiviti tanam semula yang relevan dalam skop audit semasa. Jika organisasi mempunyai rancangan jangka panjang, klausa ini perlu disemak sebagai bukti pematuhan.') ON CONFLICT (klausa_kod, status) DO NOTHING;
