INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.3.3.2', 'OFI', 'Semakan mendapati bukti bagi klausa 4.3.3.2 berkaitan Peta dengan skala yang sesuai menunjukkan tahap hak adat hendaklah disediakan kepada pihak berkepentingan yang berkaitan telah dikemukakan, namun maklumat sokongan masih boleh diperkukuh untuk memudahkan pengesahan audit.', 'Lengkapkan bukti sokongan, kemas kini rekod, tetapkan PIC dan nyatakan tempoh tindakan bagi penambahbaikan.', 'Fail 5: Peta Blok; Fail 3: Perjanjian Peserta', 'Semak ketersediaan peta hak adat dan pengesahan bertulis.', 'N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.') ON CONFLICT (klausa_kod, status) DO NOTHING;
INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.3.3.2', 'NC', 'Bukti wajib bagi klausa 4.3.3.2 tidak dikemukakan atau tidak mencukupi semasa audit. Pelaksanaan berkaitan Peta dengan skala yang sesuai menunjukkan tahap hak adat hendaklah disediakan kepada pihak berkepentingan yang berkaitan tidak dapat disahkan.', 'Sediakan dan laksanakan bukti wajib bagi klausa 4.3.3.2, lengkapkan rekod pelaksanaan dan kemukakan bukti penutupan tindakan pembetulan.', 'Fail 5: Peta Blok; Fail 3: Perjanjian Peserta', 'Semak ketersediaan peta hak adat dan pengesahan bertulis.', 'N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.') ON CONFLICT (klausa_kod, status) DO NOTHING;
INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.3.3.2', 'Pending', 'Semakan klausa 4.3.3.2 berkaitan Peta dengan skala yang sesuai menunjukkan tahap hak adat hendaklah disediakan kepada pihak berkepentingan yang berkaitan masih menunggu pelaksanaan atau pengesahan bukti. Bukti rujukan: Fail 5: Peta Blok; Fail 3: Perjanjian Peserta.', 'Laksanakan semakan, lengkapkan bukti dan kemas kini status selepas dokumen atau tapak disahkan.', 'Fail 5: Peta Blok; Fail 3: Perjanjian Peserta', 'Semak ketersediaan peta hak adat dan pengesahan bertulis.', 'N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.') ON CONFLICT (klausa_kod, status) DO NOTHING;
INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.3.3.2', 'N/A', 'Status N/A hanya diterima jika disokong justifikasi. N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.', 'Simpan bukti pengesahan N/A dan semak semula status jika terdapat perubahan operasi, skop atau aktiviti ladang.', 'Fail 5: Peta Blok; Fail 3: Perjanjian Peserta', 'Semak ketersediaan peta hak adat dan pengesahan bertulis.', 'N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.') ON CONFLICT (klausa_kod, status) DO NOTHING;
INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.3.3.3', 'C', 'Berdasarkan semakan Fail 5: Daftar Undang-Undang; Fail 3: Perjanjian; Fail 6: Minit Stakeholder. Bukti mencukupi bagi klausa 4.3.3.3 berkaitan Pelaksanaan FPIC direkodkan dan salinan perjanjian yang dirundingkan disediakan kepada pihak berkepentingan yang berkaitan atas permintaan. Pematuhan dapat disahkan semasa audit.', 'Kekalkan rekod, kawalan versi dan bukti pelaksanaan. Pastikan dokumen mudah dicapai untuk audit seterusnya.', 'Fail 5: Daftar Undang-Undang; Fail 3: Perjanjian; Fail 6: Minit Stakeholder', 'Semak rekod FPIC dan salinan perjanjian berkaitan.', 'N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.') ON CONFLICT (klausa_kod, status) DO NOTHING;
INSERT INTO public.bank_jawapan (klausa_kod, status, catatan_bukti, tindakan_pembetulan, dokumen_bukti_wajib, semakan_tapak, panduan_na) VALUES ('4.3.3.3', 'OFI', 'Semakan mendapati bukti bagi klausa 4.3.3.3 berkaitan Pelaksanaan FPIC direkodkan dan salinan perjanjian yang dirundingkan disediakan kepada pihak berkepentingan yang berkaitan atas permintaan telah dikemukakan, namun maklumat sokongan masih boleh diperkukuh untuk memudahkan pengesahan audit.', 'Lengkapkan bukti sokongan, kemas kini rekod, tetapkan PIC dan nyatakan tempoh tindakan bagi penambahbaikan.', 'Fail 5: Daftar Undang-Undang; Fail 3: Perjanjian; Fail 6: Minit Stakeholder', 'Semak rekod FPIC dan salinan perjanjian berkaitan.', 'N/A sesuai jika tiada tanah yang dibebani hak adat atau Native Customary Rights dalam skop operasi. Justifikasi perlu disokong dengan semakan dokumen tanah dan pengesahan auditee.') ON CONFLICT (klausa_kod, status) DO NOTHING;
